#include <stdio.h>

int main() {
    int T; if (scanf("%d", &T) != 1) return 0;
    while (T--) {
        int N; long long K; scanf("%d %lld", &N, &K);
        char ans[1005];
        for (int i = 0; i < N; ++i) {
            long long d; scanf("%lld", &d);
            ans[i] = (d % K == 0) ? '1' : '0';
        }
        ans[N] = '\0';
        printf("%s\n", ans);
    }
    return 0;
}

